// Normaliza o payload do site (POST /api/chat → este webhook).
const b = $json.body ?? $json;
const msg = b.message ?? {};
const sessionId = String(b.sessionId ?? '').slice(0, 64);
const mode = b.mode === 'proposal' ? 'proposal' : 'practice';
const locale = b.locale === 'en' ? 'en' : 'pt';
let type = msg.type;
let chatInput = '';

if (type === 'text') {
  chatInput = String(msg.text ?? '');
}
if (type === 'control') {
  type = 'text';
  chatInput = msg.action === 'confirm_send'
    ? '[ACAO_SISTEMA] O cliente clicou em "Enviar para o Rafael". Chame AGORA a tool finalizar_atendimento com todos os dados coletados e depois agradeça em uma mensagem curta. Responda com status "finalized" e tool "finalizar_atendimento".'
    : '[ACAO_SISTEMA] O cliente quer editar as respostas. Liste brevemente o que você registrou até aqui e pergunte o que ele quer corrigir. Responda com status "qualifying".';
}

return [{
  json: {
    sessionId,
    mode,
    locale,
    type: type ?? 'text',
    chatInput,
    data: msg.data ?? null,
    mimeType: msg.mimeType ?? null,
    duration: msg.duration ?? null,
  },
}];

// Converte o base64 do site em binário para o Whisper.
return [{
  json: { sessionId: $json.sessionId, mode: $json.mode, locale: $json.locale },
  binary: {
    data: {
      data: $json.data,
      mimeType: $json.mimeType || 'audio/webm',
      fileName: 'audio.webm',
    },
  },
}];

const src = $('Entrada').first().json;
return [{
  json: {
    sessionId: src.sessionId,
    mode: src.mode,
    locale: src.locale,
    chatInput: `[AUDIO transcrito] ${$json.text ?? ''}`,
  },
}];

// Converte o base64 do site em binário para o GPT-4o (visão).
return [{
  json: { sessionId: $json.sessionId, mode: $json.mode, locale: $json.locale },
  binary: {
    data: {
      data: $json.data,
      mimeType: $json.mimeType || 'image/jpeg',
      fileName: 'imagem.jpg',
    },
  },
}];

const src = $('Entrada').first().json;
return [{
  json: {
    sessionId: src.sessionId,
    mode: src.mode,
    locale: src.locale,
    chatInput: `[IMAGEM enviada pelo cliente] Descrição: ${$json.content ?? $json.text ?? ''}`,
  },
}];

// O agente responde JSON puro; aqui garantimos o contrato do site
// { reply, status, stage?, tool? } com fallback seguro.
const raw = String($json.output ?? $json.text ?? '');
let out = null;
try {
  const m = raw.match(/\{[\s\S]*\}/);
  if (m) out = JSON.parse(m[0]);
} catch (e) {
  out = null;
}
if (!out || typeof out.reply !== 'string' || !out.reply.trim()) {
  out = { reply: raw.replace(/```json|```/g, '').trim(), status: 'qualifying' };
}
const status = ['qualifying', 'qualified', 'finalized'].includes(out.status) ? out.status : 'qualifying';
const res = { reply: out.reply.slice(0, 4000), status };
if (out.stage) res.stage = String(out.stage).slice(0, 120);
if (out.tool) res.tool = String(out.tool).slice(0, 120);
return [{ json: res }];
